import React, { useState } from 'react';
import MainLayout from './components/Layout/MainLayout';
import KnowledgeBaseList from './components/KnowledgeBase/KnowledgeBaseList';
import CreateModal from './components/Modal/CreateModal';
import Button from './components/UI/Button';
import { Plus } from 'lucide-react';
import { useLocalStorage } from './hooks/useLocalStorage';

function App() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [knowledgeBases, setKnowledgeBases] = useLocalStorage('knowledgeBases', []);
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(10);

  const handleCreateKnowledgeBase = (newKnowledgeBase) => {
    setKnowledgeBases([newKnowledgeBase, ...knowledgeBases]);
    setCurrentPage(1);
  };

  const handleCardClick = (knowledgeBase) => {
    console.log('Clicked:', knowledgeBase);
    // You can add navigation or detail view here
  };

  return (
    <MainLayout>
      <div className="mb-6 flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-secondary">Knowledge Bases</h1>
          <p className="text-gray-500 mt-1">Manage and organize your knowledge repositories</p>
        </div>
        <Button onClick={() => setIsModalOpen(true)} variant="primary" size="lg">
          <Plus size={18} />
          Create New
        </Button>
      </div>

      <KnowledgeBaseList 
        knowledgeBases={knowledgeBases}
        onCardClick={handleCardClick}
        currentPage={currentPage}
        itemsPerPage={itemsPerPage}
        onPageChange={setCurrentPage}
      />

      <CreateModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onCreate={handleCreateKnowledgeBase}
      />
    </MainLayout>
  );
}

export default App;
